56	            on_stack: true,
57	            ready: AtomicBool::new(false),
58	            msg: UnsafeCell::new(None),
59	        }
60	    }
61	
62	    /// Creates an empty packet on the heap.
63	    fn empty_on_heap() -> Box<Self> {
64	        Box::new(Self {
65	            on_stack: false,
66	            ready: AtomicBool::new(false),
67	            msg: UnsafeCell::new(None),
68	        })
69	    }
